@using sv_faa5720868174e49ab094995e2ace872.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Profile Settings</h4>

@if (_profile is null)
{
    <p>Loading...</p>
    return;
}

@if (!string.IsNullOrEmpty(_statusMessage))
{
    <div class="alert @(_isSuccess ? "alert-success" : "alert-danger") alert-dismissible fade show" role="alert">
        @_statusMessage
        <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
    </div>
}

<div class="row">
    <!-- Avatar Preview -->
    <div class="col-md-4 text-center mb-4">
        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle mb-3" width="120" height="120"
             style="object-fit: cover; border: 3px solid var(--bs-border-color);" />
        <div class="text-muted small text-break">@_avatarUrl</div>
    </div>

    <!-- Editable Fields -->
    <div class="col-md-8">
        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Avatar URL</label>
            <input type="url" class="form-control" @bind="_avatarUrl" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>
    </div>
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isSuccess;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        LoadFromProfile(_profile);
    }

    private void LoadFromProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _statusMessage = "Profile saved successfully!";
            _isSuccess = true;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isSuccess = false;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_profile is not null)
        {
            LoadFromProfile(_profile);
            _statusMessage = null;
        }
    }
}

@using sv_faa5720868174e49ab094995e2ace872.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Notification Preferences</h4>

@if (_prefs is null)
{
    <p>Loading...</p>
    return;
}

@if (!string.IsNullOrEmpty(_statusMessage))
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        @_statusMessage
        <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
    </div>
}

<div class="mb-4">
    <h6 class="fw-semibold mb-3">General</h6>

    <div class="form-check form-switch mb-3">
        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
        <label class="form-check-label" for="emailNotif">Email Notifications</label>
        <div class="form-text">Receive notifications via email</div>
    </div>

    <div class="form-check form-switch mb-3">
        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
        <label class="form-check-label" for="pushNotif">Push Notifications</label>
        <div class="form-text">Receive push notifications in your browser</div>
    </div>

    <div class="form-check form-switch mb-3">
        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        <div class="form-text">Get a weekly summary of activity</div>
    </div>
</div>

<div class="mb-4">
    <h6 class="fw-semibold mb-3">Muted Channels</h6>
    <p class="text-muted small">Uncheck channels you want to mute.</p>

    @foreach (var channel in _allChannels)
    {
        <div class="form-check mb-2">
            <input class="form-check-input" type="checkbox" id="ch-@channel"
                   checked="@(!_mutedChannels.Contains(channel))"
                   @onchange="(e) => ToggleChannel(channel, (bool)(e.Value ?? false))" />
            <label class="form-check-label" for="ch-@channel">
                #@channel
            </label>
            @if (_mutedChannels.Contains(channel))
            {
                <span class="badge bg-secondary ms-2">Muted</span>
            }
        </div>
    }
</div>

<button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
    @if (_saving)
    {
        <span class="spinner-border spinner-border-sm me-1"></span>
    }
    Save Preferences
</button>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _saving;
    private string? _statusMessage;

    private readonly string[] _allChannels = ["general", "engineering", "marketing", "social", "announcements", "random"];

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleChannel(string channel, bool enabled)
    {
        if (enabled)
            _mutedChannels.Remove(channel);
        else
            _mutedChannels.Add(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        try
        {
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _statusMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_faa5720868174e49ab094995e2ace872.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Security Settings</h4>

@if (_settings is null)
{
    <p>Loading...</p>
    return;
}

@if (!string.IsNullOrEmpty(_statusMessage))
{
    <div class="alert @(_isSuccess ? "alert-success" : "alert-danger") alert-dismissible fade show" role="alert">
        @_statusMessage
        <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
    </div>
}

<!-- Change Password Panel -->
<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center" style="cursor: pointer;"
         @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
        <span class="fw-semibold">Change Password</span>
        <i class="bi @(_passwordPanelOpen ? "bi-chevron-up" : "bi-chevron-down")"></i>
    </div>
    @if (_passwordPanelOpen)
    {
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Update Password
                    </button>
                </div>
                <div class="col-md-6">
                    @if (_settings.LastPasswordChange.HasValue)
                    {
                        <div class="text-muted mt-2">
                            <small>Last changed: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</small>
                        </div>
                    }
                </div>
            </div>
        </div>
    }
</div>

<!-- Two-Factor Authentication -->
<div class="card mb-4">
    <div class="card-body d-flex justify-content-between align-items-center">
        <div>
            <h6 class="mb-1">Two-Factor Authentication</h6>
            <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(_twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
        </div>
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" style="transform: scale(1.3);" />
        </div>
    </div>
</div>

<!-- Active Sessions -->
<div class="card mb-4">
    <div class="card-header fw-semibold">Active Sessions</div>
    <div class="card-body p-0">
        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

<!-- Revoke Confirmation Modal -->
@if (_sessionToRevoke is not null)
{
    <div class="modal fade show d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Confirm Session Revocation</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <ul class="list-unstyled">
                        <li><strong>Device:</strong> @_sessionToRevoke.Device</li>
                        <li><strong>Location:</strong> @_sessionToRevoke.Location</li>
                        <li><strong>Last Active:</strong> @FormatLastActive(_sessionToRevoke.LastActive)</li>
                    </ul>
                    <p class="text-danger small">This action will immediately sign out the device.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private SecuritySettings? _settings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private bool _twoFactorEnabled;
    private string? _statusMessage;
    private bool _isSuccess;
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // First session is treated as the current one
    private string _currentSessionId = "sess-1";

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _statusMessage = "Please fill in all password fields.";
            _isSuccess = false;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "New password and confirmation do not match.";
            _isSuccess = false;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _statusMessage = "Password changed successfully!";
            _isSuccess = true;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to change password: {ex.Message}";
            _isSuccess = false;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _statusMessage = "Session revoked successfully.";
            _isSuccess = true;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to revoke session: {ex.Message}";
            _isSuccess = false;
        }
        finally
        {
            _revoking = false;
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

@using sv_faa5720868174e49ab094995e2ace872.Services
@inject ISettingsService SettingsService

<h4 class="mb-4">Appearance Settings</h4>

@if (_settings is null)
{
    <p>Loading...</p>
    return;
}

@if (!string.IsNullOrEmpty(_statusMessage))
{
    <div class="alert alert-success alert-dismissible fade show" role="alert">
        @_statusMessage
        <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
    </div>
}

<div class="row">
    <div class="col-md-7">
        <!-- Theme Selector -->
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Theme</h6>
            @foreach (var theme in _themes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                           value="@theme" checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="theme-@theme">@theme</label>
                </div>
            }
        </div>

        <!-- Font Size Selector -->
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Font Size</h6>
            @foreach (var size in _fontSizes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                           value="@size" checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="fs-@size">@size</label>
                </div>
            }
        </div>

        <!-- Language Dropdown -->
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Language</h6>
            <select class="form-select" style="max-width: 250px;" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">
                    <span class="fw-semibold">Compact Mode</span>
                    <div class="form-text">Reduce spacing and padding throughout the interface</div>
                </label>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save
        </button>
    </div>

    <!-- Live Preview -->
    <div class="col-md-5">
        <div class="card @GetPreviewClasses()" style="@GetPreviewStyles()">
            <div class="card-header fw-semibold">
                <i class="bi bi-eye me-1"></i> Live Preview
            </div>
            <div class="card-body">
                <h6 style="@GetPreviewFontStyle()">Sample Heading</h6>
                <p style="@GetPreviewFontStyle()" class="@(_compactMode ? "mb-1" : "mb-3")">
                    This is how your content will look with the selected settings.
                </p>
                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                    <span class="badge bg-primary">Badge</span>
                    <span class="badge bg-secondary">Item</span>
                </div>
                <button class="btn btn-sm btn-outline-primary" disabled>Sample Button</button>
            </div>
        </div>
    </div>
</div>

@code {
    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _statusMessage;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetAppearanceAsync();
        _theme = _settings.Theme;
        _fontSize = _settings.FontSize;
        _language = _settings.Language;
        _compactMode = _settings.CompactMode;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _settings = updated;
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewClasses()
    {
        return _theme == "Dark" ? "text-bg-dark" : "";
    }

    private string GetPreviewStyles()
    {
        var bg = _theme switch
        {
            "Dark" => "background-color: #1a1a2e; color: #e0e0e0; border-color: #444;",
            _ => "background-color: #ffffff; border-color: #dee2e6;"
        };

        var padding = _compactMode ? "padding: 0.5rem;" : "";
        return $"{bg} {padding}";
    }

    private string GetPreviewFontStyle()
    {
        var size = _fontSize switch
        {
            "Small" => "font-size: 0.8rem;",
            "Large" => "font-size: 1.2rem;",
            _ => "font-size: 1rem;"
        };
        return size;
    }
}

