        {
            _statusMessage = "Please fill in all password fields.";
            _isSuccess = false;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "New password and confirmation do not match.";
            _isSuccess = false;
            return;
        }

        _changingPassword = true;
        try
