            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>
    </div>
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isSuccess;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        LoadFromProfile(_profile);
    }

    private void LoadFromProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _statusMessage = "Profile saved successfully!";
            _isSuccess = true;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isSuccess = false;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_profile is not null)
        {
            LoadFromProfile(_profile);
            _statusMessage = null;
        }
    }
}

